class Solution {
    public String lastSubstring(String s) {
        int n = s.length();
        int maxIndex = 0;
        for (int i = 1; i < n; i++) {
            if (s.charAt(i) > s.charAt(maxIndex)) {
                maxIndex = i;
            } else if (s.charAt(i) == s.charAt(maxIndex)) {
                int j = maxIndex;
                while (j < n && i + j - maxIndex < n && s.charAt(i + j - maxIndex) == s.charAt(j)) {
                    j++;
                }
                if (i + j - maxIndex > maxIndex) {
                    maxIndex = i;
                }
            }
        }
        return s.substring(maxIndex);
    }
}
